return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'hu_HU','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Kérjük, frissítse a TranslatePress - Multilingual bővítményt %1$s vagy újabb verzióra, hogy a(z) %2$s megfelelően működjön.','Please install and activate the TranslatePress - Multilingual plugin'=>'Kérjük, telepítse és aktiválja a TranslatePress - Multilingual bővítményt','Install & Activate'=>'Telepítés és aktiválás','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Kérjük, frissítse a TranslatePress - Multilingual bővítményt %2$s vagy újabb verzióra. A jelenleg telepített TranslatePress - Multilingual verzió már nem kompatibilis a(z) %1$s jelenlegi verziójával.','All TranslatePress functionalities are disabled until then.'=>'A TranslatePress összes funkciója addig le van tiltva.','Update Now'=>'Frissítés most','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Ez a TranslatePress kiegészítő át lett helyezve a fő bővítménybe, és már nem használatos. Törölheti.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> futtatásához legalább PHP 5.6.20+ verzió szükséges. Ez <a href="%s">a legfrissebb WordPress verzió minimális követelménye</a>. Kérjük, vegye fel a kapcsolatot a kiszolgáló rendszergazdájával a PHP verzió frissítéséhez.','Advanced'=>'Haladó beállítások','Settings saved.'=>'Beállítások elmentve.','Are you sure you want to remove this item?'=>'Biztosan el szeretné távolítani ezt az elemet?','Remove'=>'Eltávolítás','Add'=>'Hozzáadás','Select...'=>'Kiválasztás...','[%s] Low TranslatePress AI Words'=>'[%s] Fogynak a TranslatePress AI szavak','upgrade your plan or get extra AI Words'=>'frissítse csomagját vagy szerezzen extra AI szavakat','upgrade your plan'=>'frissítse csomagját','TranslatePress AI words are running low on your site.'=>'Fogynak a TranslatePress AI szavak a weboldalán.','Current status: %s words remaining'=>'Jelenlegi állapot: %s szó maradt','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Amint a hátralévő AI szavak elfogynak, a TranslatePress AI automatikus fordítása szünetelni fog.','To continue translating your content, please %1$s over at %2$s'=>'A tartalmak fordításának folytatásához kérjük, %1$s a következő címen: %2$s','Manage Notification: %s'=>'Értesítés kezelése: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Elérhető a(z) %1$s új verziója. %2$sA %3$s verzió részleteinek megtekintése%4$s vagy %5$sFrissítés most%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Elérhető a(z) %1$s új verziója. %2$sA %3$s verzió részleteinek megtekintése%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'A frissítések engedélyezéséhez kérjük, %1$sadja meg a licenckulcsát%2$s. Licenckulcsra van szüksége? %3$sVásároljon egyet most%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'A frissítések engedélyezéséhez kérjük, menjen a %1$slicencoldal%2$sra, és ellenőrizze, hogy érvényes licenccel rendelkezik.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'A frissítések engedélyezéséhez meg kell újítania a licencét. Kérjük, látogasson el a %1$sTranslatePress Account%2$s oldalra, és jelentkezzen be a megújításhoz.','You do not have permission to install plugin updates'=>'Nincs jogosultsága bővítményfrissítések telepítéséhez.','Error'=>'Hiba','Your TranslatePress license key is invalid or missing.'=>'A TranslatePress licenckulcsa érvénytelen vagy hiányzik.','Your license key expired on %s.'=>'A licenckulcsa lejárt: %s.','Your license key has been disabled.'=>'A licenckulcsa letiltásra került.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'A licenckulcsa letiltásra került ehhez az URL-hez. Engedélyezze újra a következő helyen: <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Webhelyek kezelése.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Licenckulcs-eltérés.</strong> A megadott licenckulcs nem egyezik a telepített TranslatePress verzióval.</p><p>Kérjük, ellenőrizze, hogy a licencéhez tartozó megfelelő verziót telepítette a TranslatePress-fiókjából.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Ha csak az ingyenes bővítményt telepítette, de fizetős licencet adott hozzá, kérjük, telepítse a fizetős bővítményt a TranslatePress-fiókjából.','Your license key has reached its activation limit.'=>'A licenckulcsa elérte az aktiválási korlátot.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Frissítse a csomagját több webhely hozzáadásához. %1$sFrissítés most%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Ez a webhely már aktiválva van egy ingyenes licenccel. Minden webhely csak egy ingyenes licencet használhat.','An error occurred, please try again.'=>'Hiba történt, kérjük, próbálja újra.','You have successfully activated your license'=>'Sikeresen aktiválta a licencét.','Others'=>'Egyebek','Restrict by Language'=>'Korlátozás nyelv szerint','Exclude from Language'=>'Kizárás nyelv szerint','Restrict element to language'=>'Elem korlátozása egy nyelvre','Show this element only in one language.'=>'Az elem megjelenítése csak egy nyelven.','Enable translation'=>'Fordítás engedélyezése','Allow translation to the corresponding language only if the content is written in the default language.'=>'Fordítás engedélyezése a megfelelő nyelvre kizárólag az alapértelmezett nyelven írt tartalom esetén.','Select language'=>'Nyelv kiválasztása','Choose in which language to show this element.'=>'Válassza ki, hogy melyik nyelven jelenjen meg ez az elem.','Exclude element from language'=>'Elem kizárása nyelvekből','Exclude this element from specific languages.'=>'Az elem kizárása meghatározott nyelvekből.','Select languages'=>'Nyelvek kiválasztása','Choose from which languages to exclude this element.'=>'Válassza ki, hogy mely nyelvekből zárja ki ezt az elemet.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Ez az elem a weboldal Fordítószerkesztővel történő fordítása során is látható marad.','The content of this element should be written in the default language.'=>'Ennek az elemnek a tartalmát az alapértelmezett nyelven kell megírni.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> SQL hibákat észlelt. <a href="%s" title="TranslatePress SQL hibák megtekintése">Tekintse meg a hibákat</a>.','Automatic translation has been disabled.'=>'Az automatikus fordítás le lett tiltva.','Dismiss this notice.'=>'Értesítés elvetése.','Logged errors'=>'Naplózott hibák','These are the most recent 5 errors logged by TranslatePress:'=>'Ezek a TranslatePress által naplózott legutóbbi 5 hiba:','Yes'=>'Igen','Why are these errors occuring'=>'Miért fordulnak elő ezek a hibák','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Ha a TranslatePress hibát észlel az adatbázisban végrehajtott lekérdezések során, letilthatja az Automatikus fordítás funkciót, hogy elkerülje a Google/DeepL további díjait. Az Automatikus fordítást manuálisan kell visszakapcsolni a problémák megoldása után.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Az észlelt SQL hibák különféle okokból adódhatnak, például hiányzó táblák, az SQL felhasználó jogosultságainak hiánya táblák létrehozásához vagy más műveletek végrehajtásához, az oldal áttelepítését követő problémák, illetve az SQL szerver konfigurációjának módosításai miatt.','What you can do in this situation'=>'Mit tehet ebben a helyzetben','Plan A.'=>'A. terv','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Ugorjon a Beállítások -> TranslatePress -> Általános fülre, és mentse el a beállításokat. Ez újragenerálja a táblákat a jelenlegi SQL beállítások használatával. Ellenőrizze, hogy több hiba nem fordul-e elő, amikor a weboldalt lefordított nyelven böngészi. Nézze meg a hibák időbélyegeit, hogy megbizonyosodjon arról, nem a régi hibákat látja. Csak a legutóbbi 5 hiba jelenik meg.','Plan B.'=>'B. terv','If your problem isn\'t solved, try the following steps:'=>'Ha a problémája nem oldódott meg, próbálja meg a következő lépéseket:','Create a backup of your database'=>'Készítsen biztonsági mentést az adatbázisáról','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Készítsen másolatot minden olyan fordítási tábláról, ahol hibákat tapasztal. Másolhatja a táblát ugyanabban az adatbázisban (például trp_dictionary_en_us_es_es_COPY) -- csak akkor hajtsa végre ezt a lépést, ha meg szeretné tartani a jelenlegi fordításokat','Remove the trouble tables by executing the DROP function on them'=>'Távolítsa el a problémás táblákat a DROP funkció végrehajtásával','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Ugorjon a Beállítások -> TranslatePress -> Általános fülre, és mentse el a beállításokat. Ez újragenerálja a táblákat a jelenlegi SQL szerver használatával.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Másolja át a megfelelő tartalmat a duplikált táblákból (például trp_dictionary_en_us_es_es_COPY) az újonnan létrehozott táblába (trp_dictionary_en_us_es_es) -- csak akkor hajtsa végre ezt a lépést, ha meg szeretné tartani a jelenlegi fordításokat','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Tesztelje le, hogy minden megfelelően működik-e. Ha valami nem sikerült, visszaállíthatja az első lépésben készített biztonsági mentést. Ellenőrizze, hogy több hiba nem fordul-e elő, amikor a weboldalt lefordított nyelven böngészi. Nézze meg a hibák időbélyegeit, hogy megbizonyosodjon arról, nem a régi hibákat látja. Csak a legutóbbi 5 hiba jelenik meg.','Plan C.'=>'C. terv','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Ha a problémája továbbra sem oldódott meg, kérdezze meg tárhelyszolgáltatóját a hibákról. A leggyakoribb probléma az SQL felhasználó hiányzó jogosultságai, például a táblák létrehozására (Create Tables) vonatkozó jogosultság.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Nem sikerült telepíteni. Próbálja újra a <a href="%s" >Bővítmények irányítópultjáról.</a>','Active'=>'Aktív','Permission denied.'=>'Jogosultság megtagadva.','Invalid nonce.'=>'Érvénytelen nonce.','Settings scope unknown.'=>'Ismeretlen beállítási hatókör.','Legacy disabled.'=>'Örökölt mód letiltva.','Language Switcher'=>'Nyelvváltó','Change language to %s'=>'Nyelv módosítása %s nyelvre','Automatic Translation'=>'Automatikus fordítás','DeepL'=>'DeepL','Unsupported languages'=>'Nem támogatott nyelvek','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'A kiválasztott automatikus fordítási motor nem támogatja ezeket a nyelveket.<br>Az oldalakat továbbra is kézzel lefordíthatod ezeken a nyelveken a Fordítószerkesztő használatával.','API key validation failed.'=>'API-kulcs érvényesítése sikertelen.','API key verification was successful.'=>'API-kulcs ellenőrzése sikeres.','Please enter your Google Translate key.'=>'Kérjük, add meg a Google Translate-kulcsot.','Please enter your DeepL API key.'=>'Kérjük, add meg a DeepL API-kulcsot.','Not TranslatePress onboarding page.'=>'Nem a TranslatePress bevezető oldala.','Step %s does not exist'=>'%s. lépés nem létezik.','Welcome'=>'Üdvözlet','Add Languages'=>'Nyelvek hozzáadása','Enable Addons'=>'Kiegészítők engedélyezése','Finalize'=>'Véglegesítés','Exit Setup'=>'Kilépés a beállításból','Upgrade'=>'Frissítés','Nothing here'=>'Nincs itt semmi','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'A <strong>TranslatePress</strong> licenc hiányzik vagy érvénytelen. <br/>Kérjük, %1$sregisztrálja a példányát%2$s az automatikus weboldal-fordítás engedélyezéséhez a TranslatePress AI segítségével, valamint a prémium bővítmények, az automatikus frissítések és a támogatás eléréséhez. Licenckulcsra van szüksége? %3$sVásároljon egyet most%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'A <strong>TranslatePress</strong> licenc %1$s napján lejár. Kérjük, %2$sújítsa meg a licencét%3$s az automatikus fordításokhoz való hozzáférés folytatásához a TP AI segítségével, valamint a prémium bővítmények, a termékletöltések és az automatikus frissítések eléréséhez. %4$sMegújítás most%5$s','Error: '=>'Hiba: ','Something went wrong, please try again.'=>'Hiba történt, kérjük, próbálja újra.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'A <strong>TranslatePress</strong> licenc lejárt. <br/>Kérjük, %1$sújítsa meg a licencét%2$s az automatikus fordításokhoz való hozzáférés folytatásához a TranslatePress AI segítségével, valamint a prémium bővítmények, a termékletöltések és az automatikus frissítések eléréséhez. %3$sMegújítás most %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Licenckulcs-eltérés. A megadott licenc nem egyezik a telepített <strong>%1$s</strong> verzióval. <br/>Kérjük, ellenőrizze, hogy a licencéhez megfelelő verziót telepítette-e a %2$sTranslatePress Account%3$s oldaláról.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Ha csak az ingyenes bővítményt telepítette, de hozzáadott egy fizetős licencet, kérjük, telepítse a fizetős bővítményt a TranslatePress Account oldaláról.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Elérte a <strong>%1$s</strong> licenc aktiválási korlátját. <br/>Kezelje az aktív webhelyeit a %2$s fiókja %3$s oldalán.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'A licenc le van tiltva ehhez az URL-hez. Engedélyezze újra a következő oldalon: <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Webhelyek kezelése.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'%1$s automatikus fordításához aktív licenc szükséges. Kérjük, %2$sújítsa meg%3$s a licencét, vagy vásároljon újat %4$sitt%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Kérjük, %1$sadja meg%2$s a licenckulcsát a(z) %3$s automatikus fordítás engedélyezéséhez.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Kevesebb mint 5000 TranslatePress AI szó maradt hátra. A webhelye automatikus fordításának folytatásához %svásároljon további AI szavakat kedvezményesen a fiókja oldalán%s.',' Error: '=>' Hiba: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Ez a webhely már aktiválva van egy ingyenes licenccel. Minden webhely csak egy ingyenes licencet használhat. Kérjük, váltson prémium csomagra több TranslatePress AI szóért a %1$s fiókja %2$s oldalán.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Nincs érvényes licenc a(z) <strong>TranslatePress</strong> számára. %1$sSzerezzen egyet ingyen%2$s a TranslatePress AI eléréséhez.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>ÚJ:</strong> Megérkezett a <strong>Different Domain per Language</strong> bővítmény! Növelje globális SEO-ját, és teremtsen helyi élményt országspecifikus domainekkel, mint például a .de vagy .fr. Váltson <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business vagy Developer</a> csomagra a használatához és további prémium előnyökhöz!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>ÚJ:</strong> Megérkezett a <strong>Different Domain per Language</strong> bővítmény! Növelje globális SEO-ját, és teremtsen helyi élményt országspecifikus domainekkel, mint például a .de vagy .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Tudjon meg többet</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'A gépi fordítás napi karakterkorlátja túllépve. További információért tekintse meg a <strong>TranslatePress -> <a href="%s">Automatikus fordítás</a></strong> oldalt.','Marketing optin'=>'Marketing hozzájárulás','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Iratkozzon fel biztonsági és funkciófrissítési értesítéseinkre, valamint nem érzékeny diagnosztikai nyomkövetésünkre.','TranslatePress Preferred User Language'=>'TranslatePress előnyben részesített felhasználói nyelv','Preferred language to navigate the site'=>'Előnyben részesített nyelv az oldal böngészéséhez','The language is automatically set based by the last visited language by the user.'=>'A nyelv automatikusan a felhasználó által utoljára látogatott nyelv alapján kerül beállításra.','Always use this language'=>'Mindig ezt a nyelvet használja','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Ennek a beállításnak a bejelölésével az előnyben részesített nyelv a fent kiválasztott marad, és nem változtatható meg a frontenden.<br>Ezt a nyelvet különböző műveletek során használjuk, például e-mail küldésekor a felhasználónak.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Helló! Úgy tűnik, már egy ideje használja a <strong>TranslatePress</strong> bővítményt a weboldala fordításához. Ez nagyszerű! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Ha tudna néhány percet szánni az értékelésre a WordPress.org oldalon, az sokat segítene nekünk (és növelné a motivációmat).','~ Razvan, developer of TranslatePress'=>'~ Razvan, a TranslatePress fejlesztője','Rate TranslatePress on WordPress.org plugin page'=>'TranslatePress értékelése a WordPress.org bővítményoldalán','Ok, I will gladly help!'=>'Rendben, szívesen segítek!','No, thanks.'=>'Nem, köszönöm.','Full Language Names'=>'Teljes nyelvnevek','Short Language Names'=>'Rövid nyelvnevek','Flags with Full Language Names'=>'Zászlók teljes nyelvnevekkel','Flags with Short Language Names'=>'Zászlók rövid nyelvnevekkel','Only Flags'=>'Csak zászlók','Full Language Names No HTML'=>'Teljes nyelvnevek HTML nélkül','Bottom Right'=>'Jobb alsó','Bottom Left'=>'Bal lent','Top Right'=>'Jobb fent','Top Left'=>'Bal fent','Dark'=>'Sötét','Light'=>'Világos','Deactivate'=>'Deaktiválás','Activate'=>'Aktiválás','Invalid language code. Please try again.'=>'Érvénytelen nyelvkód. Próbálja újra.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'A nyelvkódok csak A-Z a-z 0-9 - _ karaktereket tartalmazhatnak. Ellenőrizze a nyelvkódokat a TranslatePress általános beállításaiban.','Error! Duplicate URL slug values.'=>'Hiba! Duplikált URL slug értékek.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Nem választhat ki két olyan nyelvet, amelyeknek ugyanaz az <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso kódja</a>, de eltérő a formális megjelölésük, mert ez duplikált <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang címkéket</a> eredményezne.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Duplikált nyelv észlelve.<br>Minden nyelv csak egyszer adható hozzá a pontos fordításkezelés biztosítása érdekében.<br> Módosítsa a duplikált nyelvbejegyzést, és próbálja újra. ','Current Language'=>'Aktuális nyelv','Opposite Language'=>'Ellenkező nyelv','General'=>'Általános','Translate Site'=>'Webhely fordítása','Addons'=>'Kiegészítők','License'=>'Licenc','Settings'=>'Beállítások','Activate License'=>'Licenc aktiválása','Pro Features'=>'Pro funkciók','Need Help?'=>'Segítségre van szüksége?','Recent community discussions'=>'Legutóbbi közösségi beszélgetések','Loading...'=>'Betöltés...','Unable to load forum posts'=>'Nem sikerült betölteni a fórum b